class Solution {
    public int palindromicSubstrings(String data) {
        int count = 0;
        int n = data.length();
        for (int i = 0; i < n; i++) {
            for (int j = i; j < n; j++) {
                String substring = data.substring(i, j + 1);
                if (isPalindrome(substring)) {
                    count++;
                }
            }
        }
        return count;
    }
    private boolean isPalindrome(String s) {
        int left = 0, right = s.length() - 1;
        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}

