using namespace std;
class Solution {
    public:
    int palindromicSubstrings(string data) {
        int count = 0;
        int n = data.size();
        for (int start = 0; start < n; start++) {
            for (int end = start; end < n; end++) {
                string substring = data.substr(start, end - start + 1);
                if (isPalindrome(substring)) {
                    count++;
                }
            }
        }
        return count;
    }
    private:
    bool isPalindrome(const string& str) {
        int left = 0, right = str.size() - 1;
        while (left < right) {
            if (str[left] != str[right]) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}
