#include <vector>
#include <string>
using namespace std;
class Solution {
    public:
    int palindromicSubstrings(string data) {
        int n = data.size();
        if (n == 0) return 0;
        int count = 0;
        for (int center = 0; center < 2 * n - 1; center++) {
            int left = center / 2;
            int right = left + center % 2;
            while (left >= 0 && right < n && data[left] == data[right]) {
                count++;
                left--;
                right++;
            }
        }
        return count;
    }
}
